import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {The algorithm introduces a dynamic adaptability mechanism that selects the next node based on a weighted combination of immediate travel cost, future congestion probabilities, and the urgency indicated by time-dependent bonuses to prioritize nodes as their windows of optimal accessibility narrow.}
    """
    if len(unvisited_nodes) == 0:
        return depot_node

    scores = {}

    for node in unvisited_nodes:
        distance_score = distance_matrix[current_node, node]
        congestion_probability = np.mean([1 / (1 + distance_matrix[truck, node]) for truck in truck_nodes])
        urgency_bonus = np.tanh(1 / np.log1p(distance_matrix[current_node, node]))

        scores[node] = distance_score + congestion_probability - urgency_bonus

    next_node = min(scores, key=scores.get)

    return next_node
